using System;
using System.Dynamic;
using System.Collections.Generic;

class DynamicDictionary : DynamicObject
{
    private Dictionary<string, object> _data = new Dictionary<string, object>();

    public override bool TryGetMember(GetMemberBinder binder, out object result)
    {
        return _data.TryGetValue(binder.Name, out result);
    }

    public override bool TrySetMember(SetMemberBinder binder, object value)
    {
        _data[binder.Name] = value;
        return true;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("DynamicObject istifadəsi...");
        dynamic obj = new DynamicDictionary();
        obj.Name = "Ayxan";
        obj.Age = 25;
        Console.WriteLine($"Ad: {obj.Name}");
        Console.WriteLine($"Yaş: {obj.Age}");
    }
}
// Output:
// DynamicObject istifadəsi...
// Ad: Ayxan
// Yaş: 25

using System;
using System.Dynamic;
using System.Collections.Generic;

class DynamicCalculator : DynamicObject
{
    private Dictionary<string, Func<int, int, int>> _methods = new Dictionary<string, Func<int, int, int>>
    {
        { "Add", (a, b) => a + b },
        { "Multiply", (a, b) => a * b }
    };

    public override bool TryInvokeMember(InvokeMemberBinder binder, object[] args, out object result)
    {
        if (_methods.TryGetValue(binder.Name, out var method))
        {
            result = method((int)args[0], (int)args[1]);
            return true;
        }
        result = null;
        return false;
    }
}

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Dinamik metod çağırışı...");
        dynamic calc = new DynamicCalculator();
        int sum = calc.Add(5, 3);
        int product = calc.Multiply(5, 3);
        Console.WriteLine($"Toplama: 5 + 3 = {sum}");
        Console.WriteLine($"Vurma: 5 * 3 = {product}");
    }
}
// Output:
// Dinamik metod çağırışı...
// Toplama: 5 + 3 = 8
// Vurma: 5 * 3 = 15

